:root{--bg:#08101f;--panel:#121d36;--panel2:#0d1630;--line:#26365f;--text:#f3f7ff;--muted:#91a3cb;--accent:#7c9cff;--accent2:#39d98a;--danger:#ff6b88;--warn:#f6c453}*{box-sizing:border-box}body{margin:0;font-family:Inter,system-ui,Segoe UI,Roboto,Arial,sans-serif;background:linear-gradient(180deg,#08101f,#0c1630 30%,#08101f);color:var(--text)}.hidden{display:none!important}.app{max-width:1400px;margin:0 auto;padding:20px}.auth-gate{min-height:100vh;display:grid;place-items:center;padding:24px}.auth-card{width:min(420px,100%);padding:28px;border-radius:24px;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);box-shadow:0 20px 60px rgba(0,0,0,.35)}.topbar{display:flex;justify-content:space-between;align-items:center;gap:16px;margin-bottom:20px;flex-wrap:wrap}.topbar-actions{display:flex;gap:10px;align-items:center;flex-wrap:wrap}.tabs{display:flex;gap:10px;margin-bottom:18px}.tab{border:1px solid var(--line);background:#0b1430;color:var(--muted);border-radius:999px;padding:12px 16px;font-weight:800;cursor:pointer}.tab.active{background:linear-gradient(135deg,#20346e,#385cd7);color:#fff}.grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}.panel{background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:18px;padding:16px;box-shadow:0 14px 40px rgba(0,0,0,.24)}.panel-head{display:flex;justify-content:space-between;gap:12px;align-items:start;margin-bottom:14px}.panel-head h2,.panel-head p{margin:0}.summary-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px}.summary-card{background:#0b1430;border:1px solid var(--line);border-radius:16px;padding:14px}.summary-card span{display:block;color:var(--muted);font-size:12px;margin-bottom:8px}.summary-card strong{font-size:28px}.list{display:flex;flex-direction:column;gap:10px}.item{background:#09122a;border:1px solid var(--line);border-radius:14px;padding:12px;display:grid;grid-template-columns:1fr auto auto;gap:12px;align-items:center}.item-meta{display:flex;flex-direction:column;gap:4px}.item-title{font-weight:800}.item-sub{font-size:12px;color:var(--muted)}.btn{border:none;background:#18264d;color:#fff;padding:10px 14px;border-radius:12px;cursor:pointer;font-weight:700}.btn.primary{background:linear-gradient(135deg,#5f82ff,#7c9cff)}.btn.danger{background:linear-gradient(135deg,#c23765,#ff6b88)}.btn.ghost{background:#0b1430;border:1px solid var(--line)}.pill{border:1px solid var(--line);padding:8px 12px;border-radius:999px;color:var(--muted)}.muted{color:var(--muted)}.form-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:12px}label span{display:block;font-size:12px;color:var(--muted);margin-bottom:6px}input,select,textarea{width:100%;padding:10px 12px;border-radius:12px;border:1px solid var(--line);background:#09122a;color:#fff}.forecast-toolbar{display:grid;grid-template-columns:repeat(5,1fr);gap:12px;margin-bottom:12px}.toolbar-actions{display:flex;align-items:end;height:100%}.months-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(260px,1fr));gap:14px}.month{background:#09122a;border:1px solid var(--line);border-radius:18px;padding:14px;cursor:pointer}.month h3{margin:0 0 10px}.month-rows{display:grid;grid-template-columns:1fr auto;gap:8px 10px;font-size:13px}.good{color:var(--accent2)}.bad{color:var(--danger)}.modal-root{position:fixed;inset:0;background:rgba(1,6,18,.7);display:grid;place-items:center;padding:20px;z-index:9999}.modal{width:min(1100px,100%);max-height:92vh;overflow:auto;background:linear-gradient(180deg,var(--panel),var(--panel2));border:1px solid var(--line);border-radius:18px;padding:18px}.modal-head{display:flex;justify-content:space-between;align-items:center;gap:12px;margin-bottom:14px}.modal-grid{display:grid;grid-template-columns:repeat(2,1fr);gap:16px}.inline{display:flex;gap:8px;flex-wrap:wrap}.mini-table{width:100%;border-collapse:collapse}.mini-table th,.mini-table td{border:1px solid var(--line);padding:8px;font-size:13px}.mini-table th{color:var(--muted);background:#09122a}@media (max-width: 1000px){.grid,.summary-grid,.forecast-toolbar,.modal-grid,.form-grid{grid-template-columns:1fr}}